  export function getChannelsByCategory(category: string): Channel[] {
    if (category === "all") return CHANNELS;
    return CHANNELS.filter((ch) => ch.category === category);
  }

  export function getQualityColor(quality: string | null): string {
    switch (quality) {
      case "4K": return "#a855f7";
      case "UHD": return "#3b82f6";
      case "FHD": return "#06b6d4";
      case "HD": return "#22c55e";
      case "SD": return "#f59e0b";
      default: return "#6b7280";
    }
  }
  